content:
client/styles.css
:root {
  color-scheme: light dark;
  --bg: #0f1419;
  --bg-elevated: #1a222d;
  --card: #1e2733;
  --card-border: #2d3a4a;
  --text: #e8eef4;
  --muted: #8b9cb0;
  --accent: #3b82f6;
  --accent-hover: #60a5fa;
  --accent-muted: rgba(59, 130, 246, 0.15);
  --success: #34d399;
  --warning: #fbbf24;
  --danger: #f87171;
  --radius: 12px;
  --shadow: 0 8px 32px rgba(0, 0, 0, 0.35);
}

@media (prefers-color-scheme: light) {
  :root {
    --bg: #f0f4f8;
    --bg-elevated: #ffffff;
    --card: #ffffff;
    --card-border: #e2e8f0;
    --text: #1e293b;
    --muted: #64748b;
    --accent-muted: rgba(59, 130, 246, 0.1);

client/styles.css
    --muted: #64748b;
    --accent-muted: rgba(59, 130, 246, 0.1);
    --shadow: 0 8px 24px rgba(15, 23, 42, 0.08);
  }
}

* {
  box-sizing: border-box;
}

body {
  font-family: "Inter", "Segoe UI", system-ui, sans-serif;
  margin: 0;
  min-height: 100vh;
  background: var(--bg);
  color: var(--text);
  line-height: 1.5;
}

.page-header {
  max-width: 720px;
  margin: 0 auto;
  padding: 40px 20px 16px;
}

.brand {
  display: flex;
  align-items: center;
  gap: 16px;
}

.brand-mark {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 48px;
  height: 48px;
  border-radius: 10px;

client/styles.css
  height: 48px;
  border-radius: 10px;
  background: linear-gradient(135deg, var(--accent), #6366f1);
  color: #fff;
  font-weight: 800;
  font-size: 0.85rem;
  letter-spacing: -0.04em;
}

.page-header h1 {
  margin: 0;
  font-size: 1.65rem;
  font-weight: 700;
  letter-spacing: -0.02em;
}

.subtitle {
  margin: 4px 0 0;
  color: var(--muted);
  font-size: 0.95rem;
}

.layout {
  max-width: 720px;
  margin: 0 auto;
  padding: 0 20px 48px;
  display: grid;
  gap: 20px;
}

.card {
  background: var(--card);
  border: 1px solid var(--card-border);
  border-radius: var(--radius);
  padding: 24px;

client/styles.css
  border-radius: var(--radius);
  padding: 24px;
  box-shadow: var(--shadow);
}

.section-head {
  margin-bottom: 20px;
}

.section-head h2,
.queue-header h2 {
  margin: 0 0 6px;
  font-size: 1.15rem;
  font-weight: 600;
}

.section-lead {
  margin: 0;
  color: var(--muted);
  font-size: 0.9rem;
}

.upload-zone {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 6px;
  padding: 32px 20px;
  margin-bottom: 16px;
  border: 2px dashed var(--card-border);
  border-radius: var(--radius);
  background: var(--accent-muted);
  cursor: pointer;
  transition: border-color 0.15s, background 0.15s;

client/styles.css
  cursor: pointer;
  transition: border-color 0.15s, background 0.15s;
  text-align: center;
}

.upload-zone:hover,
.upload-zone.drag-over {
  border-color: var(--accent);
  background: rgba(59, 130, 246, 0.2);
}

.upload-zone input[type="file"] {
  position: absolute;
  width: 0;
  height: 0;
  opacity: 0;
  pointer-events: none;
}

.upload-icon {
  font-size: 1.5rem;
  opacity: 0.8;
}

.upload-title {
  font-weight: 600;
  font-size: 0.95rem;
}

.upload-hint {
  font-size: 0.8rem;
  color: var(--muted);
}

.file-list {
  list-style: none;
  margin: 0 0 12px;
  padding: 0;
  display: flex;
  flex-wrap: wrap;

client/styles.css
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

.file-chip {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  max-width: 100%;
  padding: 6px 8px 6px 12px;
  border-radius: 999px;
  background: var(--bg-elevated);
  border: 1px solid var(--card-border);
  font-size: 0.85rem;
}

.file-chip-name {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  max-width: 180px;
}

.file-chip-size {
  color: var(--muted);
  font-size: 0.75rem;
  flex-shrink: 0;
}

.file-chip-remove {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 22px;
  height: 22px;

client/styles.css
  width: 22px;
  height: 22px;
  padding: 0;
  border: none;
  border-radius: 50%;
  background: transparent;
  color: var(--muted);
  font-size: 1.1rem;
  line-height: 1;
  cursor: pointer;
}

.file-chip-remove:hover {
  background: var(--card-border);
  color: var(--text);
}

.mode-hint {
  margin: 0 0 16px;
  padding: 10px 14px;
  border-radius: 8px;
  font-size: 0.85rem;
  background: var(--accent-muted);
  color: var(--text);
  border-left: 3px solid var(--accent);
}

.mode-hint[hidden] {
  display: none;
}

.settings-panel {
  margin: 20px 0;
  padding-top: 20px;
  border-top: 1px solid var(--card-border);

client/styles.css
  padding-top: 20px;
  border-top: 1px solid var(--card-border);
}

.settings-title {
  margin: 0 0 14px;
  font-size: 0.8rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  color: var(--muted);
}

.settings-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 14px;
}

.field {
  display: flex;
  flex-direction: column;
  gap: 6px;
  margin: 0;
}

.field span {
  font-size: 0.8rem;
  font-weight: 500;
  color: var(--muted);
}

.field select,
.field input {
  width: 100%;
  margin: 0;
  padding: 9px 11px;
  border: 1px solid var(--card-border);
  border-radius: 8px;

client/styles.css
  border: 1px solid var(--card-border);
  border-radius: 8px;
  background: var(--bg-elevated);
  color: var(--text);
  font-size: 0.9rem;
}

.field select:focus,
.field input:focus {
  outline: 2px solid var(--accent);
  outline-offset: 1px;
}

.finish-panel {
  margin-top: 20px;
  padding-top: 20px;
  border-top: 1px solid var(--card-border);
}

.finish-panel[hidden] {
  display: none;
}

.result-preview-wrap {
  margin: 14px 0;
  border: 1px solid var(--card-border);
  border-radius: 8px;
  overflow: hidden;
  background: #0a0a0a;
  max-height: 320px;
  display: flex;
  align-items: center;

client/styles.css
  display: flex;
  align-items: center;
  justify-content: center;
}

.result-preview {
  display: block;
  max-width: 100%;
  max-height: 320px;
  object-fit: contain;
}

.batch-finish-picker {
  margin-top: 20px;
  padding-top: 20px;
  border-top: 1px solid var(--card-border);
}

.batch-finish-picker[hidden] {
  display: none;
}

.toggle-row {
  display: grid;
  gap: 10px;
  margin-top: 14px;
}

.toggle {
  display: flex;
  align-items: center;
  gap: 10px;
  margin: 0;
  font-size: 0.88rem;
  color: var(--text);
  cursor: pointer;
}

.toggle input {
  width: auto;
  margin: 0;
  accent-color: var(--accent);

client/styles.css
  margin: 0;
  accent-color: var(--accent);
}

.analyze-panel {
  margin: 12px 0 0;
  padding: 12px;
  max-height: 220px;
  overflow: auto;
  border-radius: 8px;
  border: 1px solid var(--card-border);
  background: var(--bg-elevated);
  font-size: 0.75rem;
  line-height: 1.4;
  color: var(--muted);
  white-space: pre-wrap;
  word-break: break-word;
}

.analyze-panel[hidden] {
  display: none;
}

.action-row {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
  align-items: center;
  margin-top: 8px;
}

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 11px 18px;

client/styles.css
  justify-content: center;
  padding: 11px 18px;
  border: none;
  border-radius: 8px;
  font-size: 0.95rem;
  font-weight: 600;
  cursor: pointer;
  transition: background 0.15s, opacity 0.15s;
}

.btn.primary {
  background: var(--accent);
  color: #fff;
  flex: 1;
  min-width: 200px;
}

.btn.primary:hover:not(:disabled) {
  background: var(--accent-hover);
}

.btn.secondary {
  background: transparent;
  color: var(--accent);
  border: 1px solid var(--card-border);
}

.btn.secondary:hover:not(:disabled) {
  background: var(--accent-muted);
}

.btn:disabled {
  opacity: 0.5;
  cursor: not-allowed;

client/styles.css
  opacity: 0.5;
  cursor: not-allowed;
}

.btn.link-btn {
  padding: 0;
  background: none;
  border: none;
  color: var(--accent);
  font-weight: 500;
  font-size: 0.85rem;
  text-decoration: underline;
  min-width: auto;
}

.hint {
  margin: 0 0 10px;
  color: var(--muted);
  font-size: 0.85rem;
}

.status {
  margin: 12px 0 0;
  min-height: 1.25em;
  font-size: 0.9rem;
  color: var(--muted);
}

.status:not(:empty) {
  color: var(--text);
}

.editor-wrap {
  margin-bottom: 16px;
}

.editor-wrap[hidden] {
  display: none;
}

.editor-stage {
  position: relative;
  display: inline-block;
  max-width: 100%;

client/styles.css
  display: inline-block;
  max-width: 100%;
  border: 1px solid var(--card-border);
  border-radius: 8px;
  overflow: hidden;
  background: #0a0a0a;
}

.editor-stage canvas {
  display: block;
  max-width: 100%;
  height: auto;
  cursor: crosshair;
}

.crop-overlay {
  position: absolute;
  border: 2px solid var(--accent);
  background: rgba(59, 130, 246, 0.2);
  box-shadow: 0 0 0 9999px rgba(0, 0, 0, 0.45);
  pointer-events: none;
}

.control-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 10px 14px;
  margin-top: 14px;
}

.control-grid label {
  display: flex;
  flex-direction: column;

client/styles.css
  display: flex;
  flex-direction: column;
  gap: 4px;
  margin: 0;
  font-size: 0.8rem;
  color: var(--muted);
}

.control-grid input {
  margin: 0;
  padding: 8px 10px;
  border: 1px solid var(--card-border);
  border-radius: 8px;
  background: var(--bg-elevated);
  color: var(--text);
}

.queue-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  gap: 16px;
  margin-bottom: 16px;
}

.queue-header .hint {
  margin: 4px 0 0;
}

.queue-actions {
  display: flex;
  align-items: center;
  gap: 10px;
  flex-shrink: 0;
}

.live-badge {
  font-size: 0.7rem;
  font-weight: 700;

client/styles.css
  font-size: 0.7rem;
  font-weight: 700;
  text-transform: uppercase;
  color: var(--success);
  letter-spacing: 0.05em;
}

.live-badge[hidden] {
  display: none;
}

.queue-list {
  display: grid;
  gap: 12px;
}

.empty-queue {
  margin: 0;
  color: var(--muted);
  font-size: 0.9rem;
}

.job-card {
  border: 1px solid var(--card-border);
  border-radius: 10px;
  padding: 14px;
  background: var(--bg-elevated);
}

.job-head {
  display: flex;
  justify-content: space-between;
  gap: 12px;
  align-items: flex-start;
  margin-bottom: 10px;
}

.job-head h3 {
  margin: 0 0 4px;
  font-size: 0.95rem;

client/styles.css
  margin: 0 0 4px;
  font-size: 0.95rem;
}

.job-meta,
.meta {
  margin: 0;
  color: var(--muted);
  font-size: 0.8rem;
}

.badge {
  display: inline-block;
  padding: 4px 8px;
  border-radius: 999px;
  font-size: 0.7rem;
  font-weight: 700;
  text-transform: uppercase;
  white-space: nowrap;
}

.badge.queued {
  background: rgba(99, 102, 241, 0.25);
  color: #a5b4fc;
}

.badge.processing {
  background: rgba(251, 191, 36, 0.2);
  color: var(--warning);
}

.badge.completed {
  background: rgba(52, 211, 153, 0.2);
  color: var(--success);
}

.badge.partial {
  background: rgba(251, 191, 36, 0.15);

client/styles.css
.badge.partial {
  background: rgba(251, 191, 36, 0.15);
  color: var(--warning);
}

.badge.failed,
.badge.pending {
  background: rgba(248, 113, 113, 0.2);
  color: var(--danger);
}

.progress-row {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 12px;
}

.progress-bar {
  flex: 1;
  height: 6px;
  background: var(--card-border);
  border-radius: 999px;
  overflow: hidden;
}

.progress-fill {
  height: 100%;
  background: var(--accent);
  transition: width 0.3s ease;
}

.progress-label {
  font-size: 0.8rem;
  color: var(--muted);
  white-space: nowrap;
}

.item-list {
  list-style: none;

client/styles.css
.item-list {
  list-style: none;
  margin: 0 0 12px;
  padding: 0;
  display: grid;
  gap: 6px;
}

.queue-item {
  display: grid;
  grid-template-columns: 1fr auto;
  gap: 8px;
  align-items: center;
  padding: 8px 10px;
  border-radius: 8px;
  background: var(--card);
}

.queue-item-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  align-items: center;
  justify-content: flex-end;
}

.item-name {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  font-size: 0.85rem;
}

.item-error {
  grid-column: 1 / -1;
  color: var(--danger);
  font-size: 0.78rem;
}

.job-actions {

client/styles.css

.job-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

@media (max-width: 520px) {
  .settings-grid,
  .control-grid {
    grid-template-columns: 1fr;
  }

  .action-row .btn.primary {
    min-width: 100%;
  }
}
